   202				return applied, fmt.Errorf("setting dirty flag for version %d: %w", m.Version, err)
   203			}
   204	
   205			// Execute statements.
   206			switch m.Kind {
   207			case sqlutil.KindDDL:
   208				if err := r.updateDatabaseDDL(ctx, m.Statements); err != nil {
   209					return applied, fmt.Errorf("executing DDL migration %d (%s): %w", m.Version, m.Name, err)
   210				}
   211			case sqlutil.KindDML:
   212				if err := r.applyDML(ctx, m.Statements); err != nil {
   213					return applied, fmt.Errorf("executing DML migration %d (%s): %w", m.Version, m.Name, err)
   214				}
   215			case sqlutil.KindPartitionedDML:
   216				for _, stmt := range m.Statements {
   217					if _, err := r.applyPartitionedDML(ctx, stmt); err != nil {
   218						return applied, fmt.Errorf("executing partitioned DML migration %d (%s): %w", m.Version, m.Name, err)
   219					}
   220				}
   221			}
   222	
   223			// Clear dirty flag.
   224			if err := r.setVersion(ctx, m.Version, false); err != nil {
   225				return applied, fmt.Errorf("clearing dirty flag for version %d: %w", m.Version, err)
   226			}
   227	
   228			applied++
   229		}
   230	
   231		return applied, nil
   232	}
